const sd=$getWorkflowStaticData('global');
delete sd.acc;
delete sd.runInit;

const executionId=String($execution.id ?? 'manual');
const TZ='America/Sao_Paulo';
const now=new Date();
const parts=new Intl.DateTimeFormat('en-CA',{
  timeZone:TZ,
  year:'numeric',
  month:'2-digit',
  day:'2-digit'
}).formatToParts(now);
const m={};
for(const p of parts){
  m[p.type]=p.value;
}

const year=Number(m.year);
const month=Number(m.month);
const day=Number(m.day);
let compYear=year;
let compMonth=month-1;
if(compMonth===0){
  compMonth=12;
  compYear=year-1;
}

const mm=String(compMonth).padStart(2,'0');
const competenciaYMD=compYear+'-'+mm+'-01';
const daysInCompMonth=new Date(Date.UTC(compYear,compMonth,0)).getUTCDate();
const compStart=competenciaYMD;
const compEnd=compYear+'-'+mm+'-'+String(daysInCompMonth).padStart(2,'0');

const metrics={"rulesPages":0,"rulesTotal":0,"rulesEligible":0,"rulesSkippedDay":0,"rulesSkippedExisting":0,"invoicesPrefetchCalls":0,"invoicesPrefetchCount":0,"itemBatchQueries":0,"itemsFetched":0,"createInvoices":0,"createItems":0,"updateItemInvoiceLinks":0,"updateParcelasPagas":0};
const logs=[{
  ts:new Date().toISOString(),
  level:'info',
  event:'run_init',
  executionId,
  todayDay:day,
  competenciaYMD,
  compStart,
  compEnd
}];

const runContext={
  executionId,
  startedAt:new Date().toISOString(),
  timezone:TZ,
  todayDay:day,
  competenciaYMD,
  compStart,
  compEnd,
  flags:{
    maxRulesPages:50,
    maxPrefetchPages:50,
    rulesPageSize:50,
    prefetchPageSize:200
  },
  metrics,
  logs,
  errors:[]
};

sd.runInit={
  executionId,
  startedAt:runContext.startedAt,
  competenciaYMD:runContext.competenciaYMD,
  metrics:{...runContext.metrics},
  initialLog:{...logs[0]}
};

return [{json:{runContext}}];

const sd=$getWorkflowStaticData('global');
const defaults={"rulesPages":0,"rulesTotal":0,"rulesEligible":0,"rulesSkippedDay":0,"rulesSkippedExisting":0,"invoicesPrefetchCalls":0,"invoicesPrefetchCount":0,"itemBatchQueries":0,"itemsFetched":0,"createInvoices":0,"createItems":0,"updateItemInvoiceLinks":0,"updateParcelasPagas":0};
const allowedStatus=new Set(['processed','skipped','failed']);

if(!sd.acc){
  sd.acc={
    contractVersion:'fin_v2',
    metrics:{...defaults},
    errors:[],
    logs:[],
    results:[],
    statusCounts:{processed:0,skipped:0,failed:0},
    skippedReasons:{},
    startedAt:new Date().toISOString(),
    baseMetricsApplied:false,
    baseContextApplied:false,
    prepSummarySeen:false,
    prepSummaryCount:0,
    ruleResultsReceived:0,
    malformedResults:0,
    invalidContractCount:0
  };
}

for(const it of $input.all()){
  const nowIso=new Date().toISOString();
  const j=(it && it.json && typeof it.json==='object' && !Array.isArray(it.json)) ? it.json : {};
  const itemType=String(j.itemType || '');
  const contractVersion=String(j.contractVersion || '');

  if(contractVersion!=='fin_v2'){
    sd.acc.malformedResults += 1;
    sd.acc.invalidContractCount += 1;
    sd.acc.errors.push({
      ts:nowIso,
      stage:'accumulate_results',
      reason:'invalid_contract_version',
      details:{contractVersion,payloadKeys:Object.keys(j)}
    });
    sd.acc.logs.push({
      ts:nowIso,
      level:'error',
      event:'result_invalid_contract_version',
      contractVersion,
      payloadKeys:Object.keys(j)
    });
    continue;
  }

  const runCtx=(j.runContext && typeof j.runContext==='object' && !Array.isArray(j.runContext)) ? j.runContext : null;
  if(runCtx && !sd.acc.baseMetricsApplied && runCtx.metrics && typeof runCtx.metrics==='object' && !Array.isArray(runCtx.metrics)){
    for(const [k,v] of Object.entries(runCtx.metrics)){
      const n=Number(v);
      if(Number.isFinite(n)){
        sd.acc.metrics[k]=n;
      }
    }
    sd.acc.baseMetricsApplied=true;
  }

  if(runCtx && !sd.acc.baseContextApplied){
    const baseLogs=Array.isArray(runCtx.logs) ? runCtx.logs : [];
    const baseErrors=Array.isArray(runCtx.errors) ? runCtx.errors : [];
    if(baseLogs.length>0) sd.acc.logs.push(...baseLogs);
    if(baseErrors.length>0) sd.acc.errors.push(...baseErrors);
    sd.acc.baseContextApplied=true;
    sd.acc.logs.push({
      ts:nowIso,
      level:'info',
      event:'run_base_context_ingested_v2',
      baseLogsCount:baseLogs.length,
      baseErrorsCount:baseErrors.length
    });
  }

  if(itemType==='prep_summary'){
    sd.acc.prepSummarySeen=true;
    sd.acc.prepSummaryCount=Number(sd.acc.prepSummaryCount || 0) + 1;
    sd.acc.logs.push({
      ts:nowIso,
      level:'info',
      event:'prep_summary_accumulated_v2',
      prepContext:(j.result && typeof j.result==='object') ? (j.result.prepContext ?? null) : null
    });
    continue;
  }

  if(itemType!=='rule_result'){
    sd.acc.malformedResults += 1;
    sd.acc.errors.push({
      ts:nowIso,
      stage:'accumulate_results',
      reason:'unexpected_item_type',
      details:{itemType,payloadKeys:Object.keys(j)}
    });
    sd.acc.logs.push({
      ts:nowIso,
      level:'error',
      event:'result_unexpected_item_type',
      itemType,
      payloadKeys:Object.keys(j)
    });
    continue;
  }

  const res=(j.result && typeof j.result==='object' && !Array.isArray(j.result)) ? j.result : {};
  let status=String(res.status || '');
  let reason=String(res.reason || '').trim();
  let malformedReason=null;

  if(!allowedStatus.has(status)){
    malformedReason='invalid_status';
    status='failed';
  }
  if(!reason){
    reason='missing_reason';
    malformedReason=malformedReason || 'missing_reason';
  }

  if(malformedReason){
    sd.acc.malformedResults += 1;
    sd.acc.errors.push({
      ts:nowIso,
      stage:'accumulate_results',
      reason:malformedReason,
      details:{status:res.status ?? null,reason:res.reason ?? null}
    });
    sd.acc.logs.push({
      ts:nowIso,
      level:'error',
      event:'rule_result_malformed_v2',
      malformedReason,
      rawStatus:res.status ?? null,
      rawReason:res.reason ?? null
    });
  }

  if(res.metricsDelta && typeof res.metricsDelta==='object' && !Array.isArray(res.metricsDelta)){
    for(const [k,v] of Object.entries(res.metricsDelta)){
      const n=Number(v);
      if(Number.isFinite(n)){
        sd.acc.metrics[k]=(Number(sd.acc.metrics[k])||0)+n;
      }
    }
  }
  if(Array.isArray(res.errorsDelta)){
    sd.acc.errors.push(...res.errorsDelta);
  }
  if(Array.isArray(res.logsDelta)){
    sd.acc.logs.push(...res.logsDelta);
  }

  const ruleContext=(j.ruleContext && typeof j.ruleContext==='object' && !Array.isArray(j.ruleContext)) ? j.ruleContext : {};
  const ruleId=(ruleContext.ruleId===undefined || ruleContext.ruleId===null || String(ruleContext.ruleId).trim()==='') ? null : String(ruleContext.ruleId);
  const createdCount=Array.isArray(res.createdItemIds) ? res.createdItemIds.length : 0;

  sd.acc.ruleResultsReceived=Number(sd.acc.ruleResultsReceived || 0) + 1;
  sd.acc.statusCounts[status]=Number(sd.acc.statusCounts[status] || 0) + 1;
  if(status==='skipped'){
    sd.acc.skippedReasons[reason]=Number(sd.acc.skippedReasons[reason] || 0) + 1;
  }

  sd.acc.results.push({
    ruleId,
    status,
    reason,
    invoiceId:res.invoiceId ?? null,
    createdCount,
    timings:res.timings ?? null,
    prefetchDecision:ruleContext.prefetchDecision ?? null
  });

  sd.acc.logs.push({
    ts:nowIso,
    level:'info',
    event:'rule_result_accumulated_v2',
    ruleId,
    status,
    reason,
    createdCount
  });
}

return $input.all();

const sd=$getWorkflowStaticData('global');
const defaults={"rulesPages":0,"rulesTotal":0,"rulesEligible":0,"rulesSkippedDay":0,"rulesSkippedExisting":0,"invoicesPrefetchCalls":0,"invoicesPrefetchCount":0,"itemBatchQueries":0,"itemsFetched":0,"createInvoices":0,"createItems":0,"updateItemInvoiceLinks":0,"updateParcelasPagas":0};

const runInit=(sd.runInit && typeof sd.runInit==='object' && !Array.isArray(sd.runInit)) ? sd.runInit : {};
const acc=(sd.acc && typeof sd.acc==='object' && !Array.isArray(sd.acc)) ? sd.acc : null;

const metrics={...defaults};
if(runInit.metrics && typeof runInit.metrics==='object' && !Array.isArray(runInit.metrics)){
  for(const [k,v] of Object.entries(runInit.metrics)){
    const n=Number(v);
    if(Number.isFinite(n)) metrics[k]=n;
  }
}
if(acc && acc.metrics && typeof acc.metrics==='object' && !Array.isArray(acc.metrics)){
  for(const [k,v] of Object.entries(acc.metrics)){
    const n=Number(v);
    if(Number.isFinite(n)) metrics[k]=n;
  }
}

const sc={processed:0,skipped:0,failed:0,...(acc?.statusCounts||{})};
const processedRules=Number(sc.processed||0);
const skippedRules=Number(sc.skipped||0);
const failedRules=Number(sc.failed||0);

const accErrors=Array.isArray(acc?.errors) ? acc.errors : [];
const accLogs=Array.isArray(acc?.logs) ? acc.logs : [];
const malformedResults=Number(acc?.malformedResults || 0);
const prepSummarySeen=Boolean(acc?.prepSummarySeen);
const prepSummaryCount=Number(acc?.prepSummaryCount || 0);
const ruleResultsReceived=Number(acc?.ruleResultsReceived || (Array.isArray(acc?.results) ? acc.results.length : 0));
const warningsCount=accLogs.filter((entry)=>{
  const lvl=String(entry?.level || '').toLowerCase();
  return lvl==='warn' || lvl==='warning';
}).length;

const eligibleRulesExpected=Number(metrics.rulesEligible || 0);
const integrityErrors=[];
if(eligibleRulesExpected>0 && ruleResultsReceived===0){
  integrityErrors.push('eligible_rules_not_processed');
}

const skippedReasons=(acc?.skippedReasons && typeof acc.skippedReasons==='object' && !Array.isArray(acc.skippedReasons)) ? acc.skippedReasons : {};

const summary={
  contractVersion:'fin_v2',
  metrics,
  errorsCount:accErrors.length,
  warningsCount,
  logsCount:accLogs.length,
  malformedResults,
  prepSummarySeen,
  prepSummaryCount,
  eligibleRulesExpected,
  ruleResultsReceived,
  integrityErrors,
  processedRules,
  skippedRules,
  failedRules,
  skippedReasons,
  statusCounts:sc,
  totalRules:processedRules+skippedRules+failedRules,
  startedAt:runInit.startedAt || null,
  competenciaYMD:runInit.competenciaYMD || null,
  executionId:runInit.executionId || null
};

let run;
if(acc){
  run=acc;
}else{
  const fallbackLogs=[];
  if(runInit.initialLog && typeof runInit.initialLog==='object' && !Array.isArray(runInit.initialLog)){
    fallbackLogs.push(runInit.initialLog);
  }
  fallbackLogs.push({
    ts:new Date().toISOString(),
    level:'warn',
    event:'run_no_rule_results',
    reason:'no_results_from_process_workflow'
  });
  run={
    contractVersion:'fin_v2',
    metrics,
    errors:[],
    logs:fallbackLogs,
    results:[],
    statusCounts:sc,
    skippedReasons:{},
    malformedResults:0,
    prepSummarySeen:false,
    prepSummaryCount:0,
    ruleResultsReceived:0
  };
}

if(!Array.isArray(run.logs)){
  run.logs=[];
}
if(!prepSummarySeen){
  run.logs.push({
    ts:new Date().toISOString(),
    level:'warn',
    event:'prep_summary_missing',
    reason:'no_prep_summary_result_received'
  });
}
if(integrityErrors.length>0){
  run.logs.push({
    ts:new Date().toISOString(),
    level:'error',
    event:'run_integrity_error',
    integrityErrors,
    eligibleRulesExpected,
    ruleResultsReceived
  });
  run.errors.push({
    ts:new Date().toISOString(),
    stage:'finalize_summary',
    reason:'integrity_error',
    details:{integrityErrors,eligibleRulesExpected,ruleResultsReceived}
  });
}

const ok=(failedRules===0) && (summary.errorsCount===0) && (summary.malformedResults===0) && integrityErrors.length===0;
if(!ok){
  run.logs.push({
    ts:new Date().toISOString(),
    level:'error',
    event:'run_marked_not_ok',
    failedRules,
    errorsCount:summary.errorsCount,
    malformedResults:summary.malformedResults,
    integrityErrorsCount:integrityErrors.length
  });
}

summary.errorsCount=Array.isArray(run.errors) ? run.errors.length : summary.errorsCount;
summary.logsCount=Array.isArray(run.logs) ? run.logs.length : summary.logsCount;

return [{json:{summary,run,ok}}];

const nowIso=new Date().toISOString();
const src=($json && typeof $json==='object' && !Array.isArray($json)) ? $json : {};

if(src.contractVersion==='fin_v2' && (src.itemType==='prep_summary' || src.itemType==='rule_result')){
  return [{json:src}];
}

const trace=(src.trace && typeof src.trace==='object' && !Array.isArray(src.trace))
  ? src.trace
  : {
      parentExecutionId:null,
      workflowExecutionId:String($execution.id ?? 'manual'),
      procKey:null
    };

return [{json:{
  contractVersion:'fin_v2',
  itemType:'rule_result',
  trace,
  runContext:(src.runContext && typeof src.runContext==='object' && !Array.isArray(src.runContext)) ? src.runContext : {},
  ruleContext:(src.ruleContext && typeof src.ruleContext==='object' && !Array.isArray(src.ruleContext)) ? src.ruleContext : {ruleId:null},
  result:{
    status:'failed',
    reason:'unexpected_loop_item_type',
    invoiceId:null,
    createdItemIds:[],
    details:{
      itemType:src.itemType ?? null,
      contractVersion:src.contractVersion ?? null,
      payloadKeys:Object.keys(src)
    },
    metricsDelta:{},
    errorsDelta:[{ts:nowIso,stage:'loop_routing',reason:'unexpected_loop_item_type',details:{itemType:src.itemType ?? null,payloadKeys:Object.keys(src)}}],
    logsDelta:[{ts:nowIso,level:'error',event:'unexpected_loop_item_type',itemType:src.itemType ?? null,payloadKeys:Object.keys(src)}],
    timings:{startedAt:null,finishedAt:nowIso,durationMs:null}
  },
  status:'failed',
  reason:'unexpected_loop_item_type'
}}];
